var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네?","JPN":"モネ？","ENG":"Mone?","TWN":"莫妮？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네?","JPN":"モネネ？","ENG":"Monene?","TWN":"莫妮妮？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네!","JPN":"モネネ！","ENG":"Monene!","TWN":"莫妮妮！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네에!","JPN":"モネエ！","ENG":"Moneee!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"실물로 보는 건 처음인데……. 정말 예쁜 마을이야.","JPN":"実物を見るのは初めてだけど……本当にきれいな村ね。","ENG":"This is the first time I actually saw the village...","TWN":"第一次親眼看到……真是個漂亮的村莊。"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"큭, 이 거리를 선배님과 단둘이 걸을 수 있었다면…….","JPN":"この景色を先輩と二人きりで観ながら散歩できたなら……","ENG":"If I could walk this street with Dark...","TWN":"嗚，真希望能和前輩單獨走在這條街上……"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"오늘에야말로 내 진심을 고백할 수 있었을지도 모르는데……!","JPN":"今日こそ私の気持ちを告白できたかもしれないのに……!","ENG":"Maybe I’d be able to confess my love for him...","TWN":"今天或許很適合告白……!"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래! 지금 가자! 선배님을 찾아가서 말씀드리는 거야!","JPN":"そうだ！　今行こう！　先輩のところに行って話をしよう！","ENG":"Yes, let’s go! I’ll tell Dark!","TWN":"沒錯！現在就去吧！去跟前輩告白！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"선배님과 함께 최강의 악당이 되고 싶다고!","JPN":"先輩と一緒に最強の悪党になりたいって！","ENG":"That I want to be the ultimate villain along with him!","TWN":"我要和前輩一起成爲地表最強反派！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하하하하하하! 아하하하하하!","JPN":"ハハハハハハハ！　アハハハハ！","ENG":"Hah hah hah hah! Ah hah hah hah!","TWN":"哈哈哈哈哈！哇哈哈哈哈哈！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……하, 하?","JPN":"……ハ……ハ……？","ENG":"... Hah... Hah?","TWN":"…哈，哈！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"그렇지만 곤란하네요. 마실 것도 먹을 것도 잔뜩 준비해 뒀는데 이래선 손님이 없어요.","JPN":"困りましたね。飲み物も食べ物もいっぱい用意したのに、お客さんがいないなんて。","ENG":"What do I do? I brought so much food and drinks, but we don’t have any customers here.","TWN":"真是尷尬，準備這麼多飲料和食物，結果卻沒客人上門。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗, 손님 필요하세요? 제가 가서 모셔들 올까요?","JPN":"あっ、お客様が必要ですか？　私が連れてきましょうか？","ENG":"Do you need customers? Shall I go get them?","TWN":"喔？你需要客人嗎？要我去帶客人來？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그건 납치지 말임다?!","JPN":"それは攫ってくるってことっすか！？","ENG":"Isn’t that kidnapping, ma’am?","TWN":"那應該是綁架吧？！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 그 난리가 났는데 누가 여기 오려고 하겠어.","JPN":"ふん。あんな大騒ぎになったのに、誰がここに来ようとするのよ。","ENG":"Hmpf, no one will come here after all this.","TWN":"哼，發生這種事誰還敢來這裡？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"결국 <color=#ffd34c>그리고 모두 다 행복하게 살았습니다</color> 엔딩은 동화책에나 나오는 거지, 뭐.","JPN":"結局<color=#ffd34c>そしてずっと幸せに暮らしましたとさ。めでたし、めでたし。</color>の結末なんか童話だけの話なの。","ENG":"So, <color=#ffd34c>”everyone lived happily ever after”</color> is something from a fairy tale.","TWN":"<color=#ffd34c>大家一起度著幸福快樂的日子</color>，這種結局只會在童話裡出現吧！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};